import Module from 'module';
import url from 'url';
import applyInterop from './applyInterop.js';
import moduleType from './moduleType.js';
import supportsESM from './supportsESM.js';
import supportsSyncRequireESM from './supportsSyncRequireESM.js';
const _require = typeof require === 'undefined' ? Module.createRequire(import.meta.url) : require;
export default function loadModule(filePath, optionsOrCallback, maybeCallback) {
    let options;
    let callback;
    if (typeof optionsOrCallback === 'function') {
        options = {};
        callback = optionsOrCallback;
    } else {
        options = optionsOrCallback;
        callback = maybeCallback;
    }
    const type = options.moduleType === 'auto' || !options.moduleType ? moduleType(filePath) : options.moduleType;
    if (type === 'commonjs') {
        try {
            const mod = _require(filePath);
            callback(null, applyInterop(mod, options));
        } catch (err) {
            callback(err);
        }
        return;
    }
    // ESM
    if (!supportsESM()) {
        callback(new Error(`ESM requires Node 12+. Current: ${process.version}`));
        return;
    }
    if (supportsSyncRequireESM()) {
        // Node 23+: sync require works on ESM
        try {
            const mod = _require(filePath);
            callback(null, applyInterop(mod, options));
        } catch (err) {
            callback(err);
        }
        return;
    }
    // Node 12-22: use import()
    // ESM build: preserved as import()
    // CJS build: transpiled to require() - will fail on .mjs, but that's expected
    // Convert to file URL for Windows compatibility (import() requires file:// URLs on Windows)
    const fileUrl = url.pathToFileURL(filePath).href;
    import(fileUrl).then((mod)=>callback(null, applyInterop(mod, options))).catch((err)=>callback(err));
}
